import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.CHeM0PsO.js";const m=JSON.parse('{"title":"Instance identity — instanceId field and terminology cleanup","description":"","frontmatter":{"rfc":"0039","title":"Instance identity — instanceId field and terminology cleanup","status":"Implemented","date":"June 2026","author":"kasunben","scope":"packages/db, packages/sdk, runtime, plugins/console, packages/ui, docs","incorporated_into_plan":"Yes — implemented in runtime@0.33.0, sdk@1.13.0, db@1.7.3"},"headers":[],"relativePath":"rfcs/0039-instance-id-and-terminology.md","filePath":"rfcs/0039-instance-id-and-terminology.md"}'),i={name:"rfcs/0039-instance-id-and-terminology.md"};function d(c,e,s,r,l,u){return a(),n("div",null,[...e[0]||(e[0]=[o('<h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Two related changes shipped together:</p><ol><li><p><strong><code>instanceId</code></strong> — a stable UUID added to <code>platform_settings</code> at bootstrap that uniquely identifies a Sovereign installation. Exposed via <code>sdk.platform.getConfig().instanceId</code>. Useful for federated contexts, licensing checks, and analytics.</p></li><li><p><strong>Terminology cleanup</strong> — operator-facing UI strings, capability names, and activity event names that used &quot;tenant&quot; where the correct term is &quot;instance&quot; have been updated. The underlying <code>tenants</code> table, <code>tenant_id</code> columns, and <code>DEFAULT_TENANT_ID</code> constant are intentionally unchanged — they are forward- looking multi-tenancy infrastructure.</p></li></ol><h2 id="background" tabindex="-1">Background <a class="header-anchor" href="#background" aria-label="Permalink to &quot;Background&quot;">​</a></h2><p>Sovereign uses &quot;tenant&quot; in two distinct senses:</p><ul><li><p><strong>Multi-tenancy infrastructure</strong> — <code>tenants</code> table, <code>tenant_id</code> columns on all user-scoped tables. v1 is single-tenant per deployment; the schema is designed for future multiple tenants within a single instance. These uses are correct.</p></li><li><p><strong>&quot;Tenant&quot; used where &quot;instance&quot; is meant</strong> — the Console &quot;Tenant name&quot; label, capability names <code>tenant:view</code>/<code>tenant:configure</code>, and the activity event <code>settings.tenant_name_changed</code> all referred to the entire deployment as a &quot;tenant&quot; when they meant the self-hosted Sovereign instance. This conflation makes the future multi-tenancy migration harder to reason about.</p></li></ul><h2 id="changes" tabindex="-1">Changes <a class="header-anchor" href="#changes" aria-label="Permalink to &quot;Changes&quot;">​</a></h2><h3 id="instanceid-new" tabindex="-1"><code>instanceId</code> (new) <a class="header-anchor" href="#instanceid-new" aria-label="Permalink to &quot;`instanceId` (new)&quot;">​</a></h3><ul><li><code>packages/db/src/platform-db.ts</code> — <code>bootstrapPlatformDb()</code> seeds <code>platform_settings</code> with key <code>&#39;instance_id&#39;</code> = <code>crypto.randomUUID()</code> on <code>ON CONFLICT DO NOTHING</code> (idempotent; never changes after first bootstrap). New export: <code>getInstanceId(pdb): Promise&lt;string&gt;</code>.</li><li><code>packages/sdk/src/types.ts</code> — <code>PlatformConfig.instanceId: string</code> added.</li><li><code>runtime/src/sdk-host.ts</code> — reads <code>instanceId</code> via <code>getInstanceId()</code> and includes it in <code>getConfig()</code> return.</li></ul><h3 id="capability-renames" tabindex="-1">Capability renames <a class="header-anchor" href="#capability-renames" aria-label="Permalink to &quot;Capability renames&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Old</th><th>New</th><th>Where enforced</th></tr></thead><tbody><tr><td><code>tenant:view</code></td><td><code>instance:view</code></td><td><code>runtime/src/capabilities.ts</code></td></tr><tr><td><code>tenant:configure</code></td><td><code>instance:configure</code></td><td><code>runtime/src/capabilities.ts</code></td></tr></tbody></table><p>Role presets unchanged in membership — only the string name changed. The type union <code>Capability</code> in <code>capabilities.ts</code> updated; test file updated to match.</p><h3 id="activity-event-rename" tabindex="-1">Activity event rename <a class="header-anchor" href="#activity-event-rename" aria-label="Permalink to &quot;Activity event rename&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Old</th><th>New</th></tr></thead><tbody><tr><td><code>settings.tenant_name_changed</code></td><td><code>settings.instance_name_changed</code></td></tr></tbody></table><p>Historical rows in <code>activity_log</code> are unaffected. The human-readable <code>summary</code> now reads &quot;Instance name changed to …&quot; instead of &quot;Tenant name changed to …&quot;.</p><h3 id="ui-label-fixes-console-›-settings" tabindex="-1">UI label fixes (Console › Settings) <a class="header-anchor" href="#ui-label-fixes-console-›-settings" aria-label="Permalink to &quot;UI label fixes (Console › Settings)&quot;">​</a></h3><ul><li>&quot;Tenant name&quot; → &quot;Instance name&quot; (label text only; form field <code>name=&quot;tenantName&quot;</code> and the API body key <code>tenantName</code> are unchanged — renaming the wire format would require activity log metadata migration, deferred).</li><li>&quot;Tenant name is required.&quot; → &quot;Instance name is required.&quot;</li></ul><h3 id="example-plugin-template" tabindex="-1">Example plugin template <a class="header-anchor" href="#example-plugin-template" aria-label="Permalink to &quot;Example plugin template&quot;">​</a></h3><p><code>runtime/app/(platform)/(plugins)/my-plugin/page.tsx</code> now references <code>config.instanceName</code> instead of <code>config.tenantName</code> — <code>instanceName</code> is the preferred display name (white-label name falling back to the tenant row name).</p><h3 id="storybook-docs" tabindex="-1">Storybook &amp; docs <a class="header-anchor" href="#storybook-docs" aria-label="Permalink to &quot;Storybook &amp; docs&quot;">​</a></h3><ul><li><code>DesignSystemOverview.stories.tsx</code> — &quot;tenant theming&quot; → &quot;instance theming&quot; (4 hits)</li><li><code>CLAUDE.md</code> — &quot;tenant theming&quot; / &quot;a tenant adds colour&quot; → &quot;instance theming&quot; / &quot;an instance admin adds colour&quot;</li><li><code>docs/architecture.md</code> — White-labeling section updated to reflect renamed symbols (<code>instance_config</code>, <code>InstanceProvider</code>, <code>INSTANCE_*</code>)</li><li><code>docs/sovereign-proposal-plan-srs.md</code> — capability table updated</li><li><code>docs/upgrade.md</code> — v0.33.0 notes for event name and capability renames</li><li><code>.env.example</code> — &quot;baseline for all tenants&quot; → &quot;baseline for the instance&quot;</li></ul><h3 id="what-was-not-changed" tabindex="-1">What was NOT changed <a class="header-anchor" href="#what-was-not-changed" aria-label="Permalink to &quot;What was NOT changed&quot;">​</a></h3><ul><li><code>tenants</code> table, <code>tenant_id</code> columns, <code>DEFAULT_TENANT_ID</code>, <code>getDefaultTenant()</code>, <code>setTenantName()</code> — correct multi-tenancy infrastructure, kept as-is.</li><li><code>PlatformConfig.tenantName</code> — kept; the JSDoc clarifies it is the name of the tenant row (in v1, the workspace name set in Console).</li><li>CSS comments in <code>packages/ui/src/tokens/semantic.css</code> and <code>primitives.css</code> — &quot;tenant theming&quot; there is accurate (tenants, including future ones, can override semantic tokens).</li><li>Historical RFCs and task history docs — immutable records, not updated.</li><li>SQL migration files — immutable history.</li></ul><h2 id="semver" tabindex="-1">Semver <a class="header-anchor" href="#semver" aria-label="Permalink to &quot;Semver&quot;">​</a></h2><ul><li><code>@sovereignfs/db</code> — <strong>patch</strong> <code>1.7.2 → 1.7.3</code> (new internal helper)</li><li><code>@sovereignfs/sdk</code> — <strong>minor</strong> <code>1.12.0 → 1.13.0</code> (new public field <code>instanceId</code> on <code>PlatformConfig</code>; additive, non-breaking)</li><li><code>runtime</code> — <strong>minor</strong> <code>0.32.0 → 0.33.0</code> (capability rename affects API surface)</li><li><code>plugins/console</code> — <strong>patch</strong> <code>0.14.0 → 0.14.1</code> (label text only)</li></ul><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>1.0</td><td>June 2026</td><td>Accepted and shipped</td></tr></tbody></table>',27)])])}const g=t(i,[["render",d]]);export{m as __pageData,g as default};
